    sql: `SELECT 
            TO_CHAR(DATE_TRUNC('month', r.fecha_entrega), 'YYYY-MM') AS mes,
            TO_CHAR(DATE_TRUNC('month', r.fecha_entrega), 'Month YYYY') AS mes_nombre,
            COUNT(r.id) AS total_entregas,
            COALESCE(SUM(d.cantidad), 0) AS total_kilos
          FROM reservas r
          JOIN donaciones d ON d.id = r.donacion_id
          WHERE r.estado = 'COMPLETADA' AND r.fecha_entrega IS NOT NULL
          GROUP BY DATE_TRUNC('month', r.fecha_entrega)
          ORDER BY DATE_TRUNC('month', r.fecha_entrega) DESC;`
  }}];
}

