            u.direccion,
            COUNT(r.id) AS total_entregas,
            COALESCE(SUM(CASE WHEN r.estado = 'COMPLETADA' THEN d.cantidad ELSE 0 END), 0) AS total_kilos,
            ROUND(COALESCE(SUM(CASE WHEN r.estado = 'COMPLETADA' THEN d.cantidad ELSE 0 END), 0) * 2.5) AS co2_evitado
          FROM usuarios u
          LEFT JOIN donaciones d ON d.donante_id = u.id
          LEFT JOIN reservas r ON r.donacion_id = d.id
          WHERE u.rol = 'DONANTE'
          GROUP BY u.id, u.nombre, u.email, u.direccion
          ORDER BY total_kilos DESC;`
  }}];
}

