function formatFecha(fecha) {
  if (!fecha) return '';
  return new Date(fecha).toLocaleString('es-CL', {
    timeZone: 'America/Santiago',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  });
}

function hasCoords(lat, lng) {
  return lat !== null && lat !== undefined && lat !== "" &&
         lng !== null && lng !== undefined && lng !== "";
}

function numeroMapa(valor) {
  if (valor === null || valor === undefined || valor === "") return null;
  const n = Number(String(valor).replace(",", "."));
  return Number.isFinite(n) ? n : null;
}

function mapaOSM(lat, lng, titulo = "Mapa") {
  const la = numeroMapa(lat);
  const lo = numeroMapa(lng);

  if (la === null || lo === null) {
    return `
      <div class="advertencia">
        Ingresa latitud y longitud para mostrar el mapa.
      </div>
    `;
  }

  const delta = 0.01;
  const bbox = `${lo - delta}%2C${la - delta}%2C${lo + delta}%2C${la + delta}`;
  const osmLink = `https://www.openstreetmap.org/?mlat=${la}&mlon=${lo}#map=16/${la}/${lo}`;

  return `
    <div style="margin-top:12px;">
      <p><strong>${titulo}</strong></p>
      <iframe
        width="100%"
        height="280"
        style="border:1px solid #ccc;border-radius:8px;"
        src="https://www.openstreetmap.org/export/embed.html?bbox=${bbox}&layer=mapnik&marker=${la}%2C${lo}">
      </iframe>
      <p style="font-size:12px;color:#666;">
        Mapa: © OpenStreetMap contributors
      </p>
      <a href="${osmLink}" target="_blank" style="display:inline-block;margin-top:8px;padding:9px 13px;background:#2e7d32;color:white;border-radius:6px;text-decoration:none;">
        Abrir en OpenStreetMap
      </a>
    </div>
  `;
}

function mapaPreviewHTML(idBase, titulo = "Vista previa del mapa") {
  const tituloSeguro = String(titulo).replaceAll("'", "\\'");

  return `
    <div id="${idBase}_mapa" style="margin-top:12px;"></div>

    <script>
      (function() {
        const latInput = document.getElementById('${idBase}_lat');
        const lngInput = document.getElementById('${idBase}_lng');
        const box = document.getElementById('${idBase}_mapa');

        function renderMapa() {
          if (!latInput || !lngInput || !box) return;

          const lat = Number(String(latInput.value).replace(',', '.'));
          const lng = Number(String(lngInput.value).replace(',', '.'));

          if (!Number.isFinite(lat) || !Number.isFinite(lng)) {
            box.innerHTML = '<div class="advertencia">Ingresa latitud y longitud para mostrar el mapa.</div>';
            return;
          }

          const delta = 0.01;
          const bbox = (lng - delta) + '%2C' + (lat - delta) + '%2C' + (lng + delta) + '%2C' + (lat + delta);
          const src = 'https://www.openstreetmap.org/export/embed.html?bbox=' + bbox + '&layer=mapnik&marker=' + lat + '%2C' + lng;
          const osmLink = 'https://www.openstreetmap.org/?mlat=' + lat + '&mlon=' + lng + '#map=16/' + lat + '/' + lng;

          box.innerHTML =
            '<p><strong>${tituloSeguro}</strong></p>' +
            '<iframe width="100%" height="280" style="border:1px solid #ccc;border-radius:8px;" src="' + src + '"></iframe>' +
            '<p style="font-size:12px;color:#666;">Mapa: © OpenStreetMap contributors</p>' +
            '<a href="' + osmLink + '" target="_blank" style="display:inline-block;margin-top:8px;padding:9px 13px;background:#2e7d32;color:white;border-radius:6px;text-decoration:none;">Abrir en OpenStreetMap</a>';
        }

        latInput.addEventListener('input', renderMapa);
        lngInput.addEventListener('input', renderMapa);
        renderMapa();
      })();
    </script>
  `;
}

