  return [{ json: { accionPendiente: null,
    html: htmlBase(`
      <h2>📋 Historial de donaciones por proveedor</h2>
      <div class="ok">
        <strong>Organización:</strong> ${rows[0].organizacion_nombre}
      </div>
      ${contenido}
    `)
  }}];
}

if (accion === "reservas") {
  const lista = rows.map(r => `
    <div class="card">
      <h3>${r.producto}</h3>
      <p><strong>Organización:</strong> ${r.organizacion_nombre}</p>
      <p><strong>Fecha reserva:</strong> ${formatFecha(r.fecha_reserva)}</p>
      <p><strong>Estado:</strong> ${r.estado}</p>
      <p><strong>QR:</strong> ${r.codigo_qr}</p>
    </div>`).join("");

  return [{ json: { accionPendiente: null,
    html: htmlBase(`<h2>Reservas</h2>${lista || "<p>No hay reservas.</p>"}`)
  }}];
}

// ── HU-11: Renderizar resultado de validación QR ─────────────────────────────
if (accion === "validar_qr") {
  if (rows.length === 0 || !rows[0].reserva_id) {
    return [{ json: { accionPendiente: null,
      html: htmlBase(`
        <h2>❌ Código QR no válido</h2>
        <div class="error">
          <p>El código ingresado <strong>no existe</strong> en el sistema. Verifica que sea correcto.</p>
        </div>
        <a href="?accion=formulario_qr">← Intentar de nuevo</a>
      `)
    }}];
  }

  const r = rows[0];

  if (r.reserva_estado === "COMPLETADA") {
    return [{ json: { accionPendiente: null,
      html: htmlBase(`
        <h2>⚠️ Código ya utilizado</h2>
        <div class="advertencia">
          <p>Este código QR <strong>ya fue canjeado</strong> en una entrega anterior.</p>
          <p><strong>Producto:</strong> ${r.producto}</p>
          <p><strong>Organización:</strong> ${r.organizacion_nombre}</p>
          <p><strong>Reserva:</strong> ${r.codigo_qr}</p>
        </div>
        <a href="?accion=formulario_qr">← Validar otro código</a>
      `)
    }}];
  }

  if (Number(r.reserva_actualizada) > 0) {
    return [{ json: { accionPendiente: null,
      html: htmlBase(`
        <h2>✅ Entrega validada correctamente</h2>
        <div class="ok">
          <p><strong>Producto:</strong> ${r.producto}</p>
          <p><strong>Cantidad:</strong> ${r.cantidad}</p>
          <p><strong>Organización receptora:</strong> ${r.organizacion_nombre}</p>
          <p><strong>Donante:</strong> ${r.donante_nombre}</p>
          <p><strong>Código QR:</strong> ${r.codigo_qr}</p>
          <p><strong>Fecha y hora de entrega:</strong> ${formatFecha(r.fecha_entrega)}</p>
          <p><strong>Estado donación:</strong> <span class="badge" style="background:#388e3c;color:white;padding:4px 8px;border-radius:5px;">ENTREGADA</span></p>
        </div>
        <p class="ok">✅ Notificación enviada al donante automáticamente.</p>
        <br>
        <a href="?accion=reservas">Ver todas las reservas</a>
      `)
    }}];
  }

  return [{ json: { accionPendiente: null,
    html: htmlBase(`
      <h2>❌ Error al validar</h2>
      <div class="error">
        <p>Ocurrió un error inesperado al procesar el código. Intenta nuevamente.</p>
      </div>
      <a href="?accion=formulario_qr">← Volver</a>
    `)
  }}];
}

// ── HU-13: Renderizar reporte de kilos rescatados ─────────────────────────────
if (accion === "reporte_kilos") {
  const total_general = rows.reduce((sum, r) => sum + Number(r.total_kilos || 0), 0);
  const total_entregas = rows.reduce((sum, r) => sum + Number(r.total_entregas || 0), 0);

  const filas = rows.map(r => `
    <tr>
      <td>${r.mes_nombre}</td>
      <td style="text-align:center;">${r.total_entregas}</td>
      <td style="text-align:center;font-weight:bold;">${Number(r.total_kilos || 0).toLocaleString('es-CL')}</td>
    </tr>
  `).join("");

  return [{ json: { accionPendiente: null,
    html: htmlBase(`
      <h2>📊 Reporte de kilos rescatados</h2>
      <div class="ok" style="display:flex;gap:30px;margin-bottom:20px;">
        <div style="text-align:center;">
          <p style="font-size:2em;font-weight:bold;margin:0;">${total_general.toLocaleString('es-CL')}</p>
          <p style="margin:0;">Total kilos rescatados</p>
        </div>
        <div style="text-align:center;">
          <p style="font-size:2em;font-weight:bold;margin:0;">${total_entregas}</p>
          <p style="margin:0;">Total entregas completadas</p>
        </div>
      </div>
      <table>
        <tr>
          <th>Mes</th>
          <th style="text-align:center;">Entregas</th>
          <th style="text-align:center;">Kilos rescatados</th>
        </tr>
        ${filas || '<tr><td colspan="3">No hay entregas completadas aún.</td></tr>'}
      </table>
    `)
  }}];
}

// ── HU-14: Renderizar certificado de impacto ambiental ───────────────────────
if (accion === "certificado") {
  if (rows.length === 0) {
    return [{ json: { accionPendiente: null,
      html: htmlBase(`
        <h2>🌱 Certificado de impacto ambiental</h2>
        <div class="advertencia">No hay donantes registrados para generar certificados.</div>
        <a href="?accion=inicio">← Volver</a>
      `)
    }}];
  }

  const certificados = rows.map(d => `
    <div class="card" style="border-left-color:#2e7d32;page-break-inside:avoid;">
      <div style="display:flex;justify-content:space-between;align-items:center;">
        <div>
          <h3 style="margin:0;">🌱 ${d.nombre}</h3>
          <p style="margin:4px 0;color:#666;">${d.email} ${d.direccion ? '— ' + d.direccion : ''}</p>
        </div>
        <span class="badge" style="background:#2e7d32;font-size:14px;padding:8px 12px;">CERTIFICADO</span>
      </div>

      <hr style="border-color:#e8f5e9;">

      <div style="display:flex;gap:30px;margin:10px 0;">
        <div style="text-align:center;">
          <p style="font-size:1.8em;font-weight:bold;margin:0;color:#2e7d32;">${Number(d.total_kilos || 0).toLocaleString('es-CL')}</p>
          <p style="margin:0;font-size:12px;">kg rescatados</p>
        </div>

        <div style="text-align:center;">
          <p style="font-size:1.8em;font-weight:bold;margin:0;color:#0277bd;">${Number(d.co2_evitado || 0).toLocaleString('es-CL')}</p>
          <p style="margin:0;font-size:12px;">kg CO₂ evitado</p>
        </div>

        <div style="text-align:center;">
          <p style="font-size:1.8em;font-weight:bold;margin:0;color:#f57c00;">${d.total_entregas || 0}</p>
          <p style="margin:0;font-size:12px;">entregas completadas</p>
        </div>
      </div>

      <p style="font-size:12px;color:#888;margin:8px 0 0 0;">
        * Estimación CO₂: 2.5 kg de CO₂ evitado por cada kg de alimento rescatado.
      </p>
    </div>
  `).join("");

  return [{ json: { accionPendiente: null,
    html: htmlBase(`
      <h2>🌱 Certificados de impacto ambiental</h2>
      <div class="advertencia">
        <strong>Metodología:</strong> Se estima que por cada kilogramo de alimento rescatado se evita la emisión de 2.5 kg de CO₂ equivalente, considerando producción, transporte y descomposición en vertedero.
      </div>
      ${certificados}
    `)
  }}];
}

return [{ json: { accionPendiente: null,
  html: htmlBase(`<h2>Acción no reconocida</h2><p>Acción: <strong>${accion}</strong></p>`)
}}];

const meta = $('Code in JavaScript').first().json;
const accion = meta.accion;
const rows = $input.all().map(i => i.json);

// Acciones que no necesitan notificaciones, pasar directo
if (accion !== 'guardar_donacion' && accion !== 'guardar_vencido') {
  return [{ json: { ...meta, rows, sqlNotif: null }}];
}

if (accion === 'guardar_donacion' || accion === 'guardar_vencido') {
  const donacion = rows[0];
  if (donacion && donacion.id) {
    const esVencido = accion === 'guardar_vencido';
    const mensaje = esVencido
      ? `⚠️ ALERTA VENCIDO: ${donacion.nombre} (${donacion.cantidad} uds) vencido el ${donacion.vencimiento}`
      : `Nueva donación: ${donacion.nombre} (${donacion.cantidad} uds) disponible`;
    return [{ json: {
      ...meta,
      rows,
      sqlNotif: `INSERT INTO notificaciones (usuario_id, organizacion_nombre, donacion_id, mensaje, es_alerta_vencido)
                 SELECT u.id, u.nombre, ${donacion.id}, '${mensaje.replaceAll("'","''")}', ${esVencido}
                 FROM usuarios u WHERE u.rol = 'ONG';`
    }}];
  }
}

return [{ json: { ...meta, rows, sqlNotif: null }}];
